import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,d as t}from"./app-21664fcf.js";const e={},o=t(`<h1 id="orm基本操作" tabindex="-1"><a class="header-anchor" href="#orm基本操作" aria-hidden="true">#</a> ORM基本操作</h1><h2 id="orm基本操作-1" tabindex="-1"><a class="header-anchor" href="#orm基本操作-1" aria-hidden="true">#</a> ORM基本操作</h2><p>针对模型类的增删改查做简单介绍。</p><h3 id="增" tabindex="-1"><a class="header-anchor" href="#增" aria-hidden="true">#</a> 增</h3><p>通过 ORM 操作，增加 对应记录的方式有两种：</p><h4 id="模型类对象操作" tabindex="-1"><a class="header-anchor" href="#模型类对象操作" aria-hidden="true">#</a> 模型类对象操作</h4><ul><li>根据模型类创建对应的对象</li><li>调用对象的<code>save</code>方法，保存对象即可</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>book <span class="token operator">=</span> Book<span class="token punctuation">(</span>btitle<span class="token operator">=</span><span class="token string">&#39;昆仑&#39;</span><span class="token punctuation">,</span> publish<span class="token operator">=</span><span class="token string">&#39;北京大学出版社&#39;</span><span class="token punctuation">,</span> price<span class="token operator">=</span><span class="token number">89</span><span class="token punctuation">,</span> bcomment<span class="token operator">=</span><span class="token number">10000</span><span class="token punctuation">,</span> bread<span class="token operator">=</span><span class="token number">3000</span><span class="token punctuation">,</span> bpub_date<span class="token operator">=</span>date<span class="token punctuation">(</span><span class="token number">2005</span><span class="token punctuation">,</span><span class="token number">8</span><span class="token punctuation">,</span><span class="token number">9</span><span class="token punctuation">)</span><span class="token punctuation">,</span> author_id<span class="token operator">=</span><span class="token number">3</span><span class="token punctuation">)</span>
book<span class="token punctuation">.</span>save<span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="模型类管理器操作" tabindex="-1"><a class="header-anchor" href="#模型类管理器操作" aria-hidden="true">#</a> 模型类管理器操作</h4><ul><li>调用模型类对应的管理器的 <code>create</code>方法，即可创建对象</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>create<span class="token punctuation">(</span>btitle<span class="token operator">=</span><span class="token string">&#39;沧海&#39;</span><span class="token punctuation">,</span> publish<span class="token operator">=</span><span class="token string">&#39;人民教育出版社&#39;</span><span class="token punctuation">,</span> price<span class="token operator">=</span><span class="token number">30</span><span class="token punctuation">,</span> author_id<span class="token operator">=</span><span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="删" tabindex="-1"><a class="header-anchor" href="#删" aria-hidden="true">#</a> 删</h3><p>通过 ORM 操作，删除 对应记录的方式有两种：</p><h4 id="模型类对象操作-1" tabindex="-1"><a class="header-anchor" href="#模型类对象操作-1" aria-hidden="true">#</a> 模型类对象操作</h4><ul><li>使用<code>get</code>方法获取对应的模型类</li><li>调用对象的<code>delete</code>方法，删除对象即可</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>book <span class="token operator">=</span> Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>get<span class="token punctuation">(</span><span class="token builtin">id</span><span class="token operator">=</span><span class="token number">13</span><span class="token punctuation">)</span>  <span class="token comment"># 获取模型对象</span>
book<span class="token punctuation">.</span>delete<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># 调用模型对象的delete方法删除</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="模型类管理器操作-1" tabindex="-1"><a class="header-anchor" href="#模型类管理器操作-1" aria-hidden="true">#</a> 模型类管理器操作</h4><ul><li>使用模型类的管理器 获取对应的查询集</li><li>调用查询集的 <code>delete</code> 方法删除对象</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>book_set <span class="token operator">=</span> Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span><span class="token builtin">id</span><span class="token operator">=</span><span class="token number">14</span><span class="token punctuation">)</span>  <span class="token comment"># 获取对应的查询集</span>
book_set<span class="token punctuation">.</span>delete<span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token comment"># 调用delete方法删除</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="改" tabindex="-1"><a class="header-anchor" href="#改" aria-hidden="true">#</a> 改</h3><p>通过 ORM 操作，修改 对应记录的方式有两种：</p><h4 id="模型类对象操作-2" tabindex="-1"><a class="header-anchor" href="#模型类对象操作-2" aria-hidden="true">#</a> 模型类对象操作</h4><ul><li>修改模型类对象的属性</li><li>执行<code>save()</code>方法</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>book <span class="token operator">=</span> Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>get<span class="token punctuation">(</span>btitle<span class="token operator">=</span><span class="token string">&#39;龙珠&#39;</span><span class="token punctuation">)</span>
book<span class="token punctuation">.</span>btitle <span class="token operator">=</span> <span class="token string">&#39;《龙珠》&#39;</span>
book<span class="token punctuation">.</span>save<span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="模型类管理器操作-2" tabindex="-1"><a class="header-anchor" href="#模型类管理器操作-2" aria-hidden="true">#</a> 模型类管理器操作</h4><ul><li>使用模型类的管理器 获取对应的查询集</li><li>调用查询集的 <code>update</code> 方法更新对象</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>book_set <span class="token operator">=</span> Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>btitle<span class="token operator">=</span><span class="token string">&#39;龙珠&#39;</span><span class="token punctuation">)</span>  <span class="token comment"># 通过管理器获取对应的查询集</span>
book_set<span class="token punctuation">.</span>update<span class="token punctuation">(</span>btitle<span class="token operator">=</span><span class="token string">&#39;《龙珠》&#39;</span><span class="token punctuation">)</span>  <span class="token comment"># 调用 update方法更新对象</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="查" tabindex="-1"><a class="header-anchor" href="#查" aria-hidden="true">#</a> 查</h3><h4 id="基本查询" tabindex="-1"><a class="header-anchor" href="#基本查询" aria-hidden="true">#</a> 基本查询</h4><p><code>get</code> 查询单一结果，如果不存在会抛出<code>模型类.DoesNotExist</code>异常</p><p><code>all</code> 查询多个结果</p><p><code>count</code> 查询结果数量</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> django<span class="token punctuation">.</span>views <span class="token keyword">import</span> View
<span class="token keyword">from</span> django<span class="token punctuation">.</span>http <span class="token keyword">import</span> JsonResponse
<span class="token keyword">from</span> <span class="token punctuation">.</span>models <span class="token keyword">import</span> Book<span class="token punctuation">,</span> Author


<span class="token keyword">class</span> <span class="token class-name">BookView</span><span class="token punctuation">(</span>View<span class="token punctuation">)</span><span class="token punctuation">:</span>

    <span class="token keyword">def</span> <span class="token function">get</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> request<span class="token punctuation">)</span><span class="token punctuation">:</span>
        books <span class="token operator">=</span> Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">all</span><span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token comment"># 获取所有图书</span>

        <span class="token keyword">if</span> books<span class="token punctuation">.</span>count<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">==</span> <span class="token number">0</span><span class="token punctuation">:</span>  <span class="token comment"># 获取查询结果的数量</span>
            <span class="token keyword">return</span> JsonResponse<span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">,</span> safe<span class="token operator">=</span><span class="token boolean">False</span><span class="token punctuation">)</span>

        booksInfo <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>  <span class="token comment"># 构造空列表， 存储所有图书信息</span>

        <span class="token keyword">for</span> book <span class="token keyword">in</span> books<span class="token punctuation">:</span>  <span class="token comment"># 遍历查询集</span>
            <span class="token keyword">try</span><span class="token punctuation">:</span>
                author <span class="token operator">=</span> Author<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>get<span class="token punctuation">(</span><span class="token builtin">id</span><span class="token operator">=</span>book<span class="token punctuation">.</span>author_id<span class="token punctuation">)</span>  <span class="token comment"># 查询图书对应的作者信息</span>
            <span class="token keyword">except</span> Exception <span class="token keyword">as</span> e<span class="token punctuation">:</span>  <span class="token comment"># get 查询不到，会抛出异常</span>
                <span class="token comment"># e:Author matching query does not exist.</span>
                authorinfo <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>
            <span class="token keyword">else</span><span class="token punctuation">:</span>
                authorinfo <span class="token operator">=</span> <span class="token punctuation">{</span>
                    <span class="token string">&quot;name&quot;</span><span class="token punctuation">:</span> author<span class="token punctuation">.</span>name<span class="token punctuation">,</span>
                    <span class="token string">&quot;age&quot;</span><span class="token punctuation">:</span> author<span class="token punctuation">.</span>age<span class="token punctuation">,</span>
                    <span class="token string">&quot;gender&quot;</span><span class="token punctuation">:</span> author<span class="token punctuation">.</span>gender
                <span class="token punctuation">}</span>

            bookinfo <span class="token operator">=</span> <span class="token punctuation">{</span>
                <span class="token string">&quot;id&quot;</span><span class="token punctuation">:</span> book<span class="token punctuation">.</span><span class="token builtin">id</span><span class="token punctuation">,</span>
                <span class="token string">&quot;btitle&quot;</span><span class="token punctuation">:</span> book<span class="token punctuation">.</span>btitle<span class="token punctuation">,</span>
                <span class="token string">&quot;publish&quot;</span><span class="token punctuation">:</span> book<span class="token punctuation">.</span>publish<span class="token punctuation">,</span>
                <span class="token string">&quot;bcomment&quot;</span><span class="token punctuation">:</span> book<span class="token punctuation">.</span>bcomment<span class="token punctuation">,</span>
                <span class="token string">&quot;bread&quot;</span><span class="token punctuation">:</span> book<span class="token punctuation">.</span>bread<span class="token punctuation">,</span>
                <span class="token string">&quot;price&quot;</span><span class="token punctuation">:</span> book<span class="token punctuation">.</span>price<span class="token punctuation">,</span>
                <span class="token string">&quot;author&quot;</span><span class="token punctuation">:</span> authorinfo
            <span class="token punctuation">}</span>
            booksInfo<span class="token punctuation">.</span>append<span class="token punctuation">(</span>bookinfo<span class="token punctuation">)</span>

        <span class="token keyword">return</span> JsonResponse<span class="token punctuation">(</span>booksInfo<span class="token punctuation">,</span> safe<span class="token operator">=</span><span class="token boolean">False</span><span class="token punctuation">)</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="过滤查询" tabindex="-1"><a class="header-anchor" href="#过滤查询" aria-hidden="true">#</a> 过滤查询</h4><h5 id="语法构造" tabindex="-1"><a class="header-anchor" href="#语法构造" aria-hidden="true">#</a> 语法构造</h5><p>实现<em>SQL</em>中的<em>where</em>功能，包括</p><ul><li><strong><code>filter</code></strong> 过滤出多个结果</li><li><strong><code>exclude</code></strong> 排除掉符合条件剩下的结果</li><li><strong><code>get</code></strong> 过滤单一结果</li></ul><p>过滤条件的表达语法如下：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>属性名称__比较运算符<span class="token operator">=</span>值
<span class="token comment"># 属性名称和比较运算符间使用两个下划线，所以属性名不能包括多个下划线</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="比较运算符" tabindex="-1"><a class="header-anchor" href="#比较运算符" aria-hidden="true">#</a> 比较运算符</h4><h5 id="比较查询" tabindex="-1"><a class="header-anchor" href="#比较查询" aria-hidden="true">#</a> 比较查询</h5><ul><li><strong><code>exact</code><strong>​</strong>：表示判断相等。</strong></li><li><strong>不等于的运算符，使用</strong>​**<code>exclude()</code><strong>​</strong>过滤器。**</li><li><strong><code>gt</code></strong> 大于 (<em>greater then</em>)</li><li><strong><code>gte</code></strong> 大于等于 (<em>greater then equal</em>)</li><li><strong><code>lt</code></strong> 小于 (<em>less then</em>)</li><li><strong><code>lte</code></strong> 小于等于 (<em>less then equal</em>)</li></ul><p><strong>1. 查询编号为1的图书。</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>BookInfo<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>id__exact<span class="token operator">=</span><span class="token number">1</span><span class="token punctuation">)</span>
<span class="token comment"># 可简写为：</span>
BookInfo<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span><span class="token builtin">id</span><span class="token operator">=</span><span class="token number">1</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>2. 查询图书 《三重门》</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>get<span class="token punctuation">(</span>btitle__exact<span class="token operator">=</span><span class="token string">&quot;三重门&quot;</span><span class="token punctuation">)</span>  <span class="token comment"># 当图书不存在,会抛出异常</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>3. 查询价格不是12.4 的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Books<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>exclude<span class="token punctuation">(</span>price__exact<span class="token operator">=</span><span class="token number">12.4</span><span class="token punctuation">)</span> <span class="token comment"># 排除 价格为12.4的图书之后，就是相反的结果</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>4. 查询编号大于3的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>BookInfo<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>id__gt<span class="token operator">=</span><span class="token number">3</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>5. 查询编号不等于3的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>BookInfo<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>exclude<span class="token punctuation">(</span><span class="token builtin">id</span><span class="token operator">=</span><span class="token number">3</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h5 id="模糊查询" tabindex="-1"><a class="header-anchor" href="#模糊查询" aria-hidden="true">#</a> 模糊查询</h5><ul><li><strong><code>contains</code><strong>​</strong>：模糊查询是否包含</strong></li><li><strong><code>startswith</code></strong>：<strong>以指定值开头</strong></li><li><strong><code>endswith</code><strong>​</strong>：以指定值结尾</strong></li></ul><blockquote><p>说明：如果要包含<code>%</code>无需转义，直接写即可。</p></blockquote><p><strong>1. 查询书名包含&#39;传&#39;的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>BookInfo<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>btitle__contains<span class="token operator">=</span><span class="token string">&#39;传&#39;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>2. 查询书名以&#39;三&#39;开头的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>btitle__startswith<span class="token operator">=</span><span class="token string">&quot;三&quot;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>3. 查询书名以&#39;门&#39;结尾的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>btitle__endswith<span class="token operator">=</span><span class="token string">&quot;门&quot;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><blockquote><p><strong>以上运算符都区分大小写，在这些运算符前加上i表示不区分大小写，如</strong>​**<code>iexact</code><strong>​</strong>、<strong>​</strong><code>icontains</code><strong>​</strong>、<strong>​</strong><code>istartswith</code><strong>​</strong>、<strong>​</strong><code>iendswith</code><strong>​</strong>.**</p></blockquote><h5 id="空查询" tabindex="-1"><a class="header-anchor" href="#空查询" aria-hidden="true">#</a> 空查询</h5><ul><li><strong><code>isnull</code><strong>​</strong>：是否为</strong>​**<code>null</code><strong>​</strong>。**</li></ul><p><strong>1. 查询书名不为空的图书</strong>。</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>BookInfo<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>btitle__isnull<span class="token operator">=</span><span class="token boolean">False</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h5 id="范围查询" tabindex="-1"><a class="header-anchor" href="#范围查询" aria-hidden="true">#</a> 范围查询</h5><ul><li><strong><code>in</code><strong>​</strong>：是否包含在范围内。</strong></li></ul><p><strong>1. 查询编号为1或3或5的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>BookInfo<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>id__in<span class="token operator">=</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h5 id="日期查询" tabindex="-1"><a class="header-anchor" href="#日期查询" aria-hidden="true">#</a> 日期查询</h5><ul><li><strong><code>year</code><strong>​</strong>、<strong>​</strong><code>month</code><strong>​</strong>、<strong>​</strong><code>day</code><strong>​</strong>、<strong>​</strong><code>week_day</code><strong>​</strong>、<strong>​</strong><code>hour</code><strong>​</strong>、<strong>​</strong><code>minute</code><strong>​</strong>、<strong>​</strong><code>second</code><strong>​</strong>：对日期时间类型的属性进行运算。</strong></li><li>比较具体的时间， 需要利用 **<code>datetime</code>**模块中的 **<code>date</code>**和 <strong><code>datetime</code></strong> 方法，自定义时间</li></ul><p><strong>1.查询1980年发表的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>BookInfo<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>bpub_date__year<span class="token operator">=</span><span class="token number">1980</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>2. 查询2000之后出版的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>bpub_date__year__gt<span class="token operator">=</span><span class="token number">2000</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>3. 查询5月之后出版的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>bpub_date__month__gt<span class="token operator">=</span><span class="token number">5</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>4.查询2005年4月5日后发表的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> datetime <span class="token keyword">import</span> date<span class="token punctuation">,</span> datetime

Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>bpub_date__lt<span class="token operator">=</span>date<span class="token punctuation">(</span><span class="token number">2005</span><span class="token punctuation">,</span><span class="token number">4</span><span class="token punctuation">,</span><span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment"># 注意：比较具体的时间，需要自己构建时间</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="f对象和q对象" tabindex="-1"><a class="header-anchor" href="#f对象和q对象" aria-hidden="true">#</a> F对象和Q对象</h4><h5 id="属性-vs-属性" tabindex="-1"><a class="header-anchor" href="#属性-vs-属性" aria-hidden="true">#</a> 属性 VS 属性</h5><blockquote><p>之前的查询都是对象的属性与常量值比较，两个属性怎么比较呢？</p><ul><li>使用<strong>F对象</strong>，被定义在<code>django.db.models</code>中。</li><li>可以在<strong>F对象</strong>上使用算数运算。</li></ul></blockquote><p><strong>语法如下：</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> django<span class="token punctuation">.</span>db<span class="token punctuation">.</span>models <span class="token keyword">import</span> F


F<span class="token punctuation">(</span><span class="token string">&#39;属性名&#39;</span><span class="token punctuation">)</span>  <span class="token comment"># 注意：属性名是字符串形式</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>1. 查询阅读量大于评论量的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>bread__gt<span class="token operator">=</span>F<span class="token punctuation">(</span><span class="token string">&#39;bcomment&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>2. 查询阅读量是评论量2倍的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>bread<span class="token operator">=</span>F<span class="token punctuation">(</span><span class="token string">&#39;bcomment&#39;</span><span class="token punctuation">)</span><span class="token operator">*</span><span class="token number">2</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>3. 查询阅读量比评论量多100的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>bread<span class="token operator">=</span>F<span class="token punctuation">(</span><span class="token string">&#39;bcomment&#39;</span><span class="token punctuation">)</span><span class="token operator">+</span><span class="token number">100</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h5 id="逻辑运算" tabindex="-1"><a class="header-anchor" href="#逻辑运算" aria-hidden="true">#</a> 逻辑运算</h5><blockquote><ul><li>多个过滤器逐个调用表示逻辑与<code>and</code>关系，同sql语句中where部分的and关键字。</li><li>如果需要实现逻辑或<code>or</code>的查询，需要使用<strong>Q对象</strong>结合<strong>逻辑运算符</strong>，<strong>Q对象</strong>被义在<code>django.db.models</code>中。</li><li>Q对象可以使用<code>&amp;</code>、<code>|</code>连接，<code>&amp;</code>表示逻辑与，<code>|</code>表示逻辑或。</li></ul></blockquote><p><strong>语法如下：</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> django<span class="token punctuation">.</span>db<span class="token punctuation">.</span>models <span class="token keyword">import</span> Q


Q<span class="token punctuation">(</span>属性名__运算符<span class="token operator">=</span>值<span class="token punctuation">)</span>  <span class="token comment"># 注意： 属性名不是字符串，不能加引号</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>1 查询id阅读量大于20且id小于3的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>bcomment__gt<span class="token operator">=</span><span class="token number">20</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>id__lt<span class="token operator">=</span><span class="token number">3</span><span class="token punctuation">)</span>  <span class="token comment"># 多个过滤器连续操作</span>

Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span> Q<span class="token punctuation">(</span>bcomment__gt<span class="token operator">=</span><span class="token number">20</span><span class="token punctuation">)</span> <span class="token operator">&amp;</span> Q<span class="token punctuation">(</span>id__lt<span class="token operator">=</span><span class="token number">3</span><span class="token punctuation">)</span> <span class="token punctuation">)</span>  <span class="token comment"># 使用Q对象和逻辑运算符</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>2 查询阅读量大于20，或编号小于3的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span> Q<span class="token punctuation">(</span>bcomment__gt<span class="token operator">=</span><span class="token number">20</span><span class="token punctuation">)</span> <span class="token operator">|</span> Q<span class="token punctuation">(</span>id__lt<span class="token operator">=</span><span class="token number">3</span><span class="token punctuation">)</span> <span class="token punctuation">)</span>  <span class="token comment"># 只能使用Q对象</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="聚合查询" tabindex="-1"><a class="header-anchor" href="#聚合查询" aria-hidden="true">#</a> 聚合查询</h4><blockquote><p>使用<code>aggregate()</code>过滤器调用聚合函数。</p><p>聚合函数被定义在<code>django.db.models</code>中</p></blockquote><ul><li><strong><code>Avg</code></strong> 平均</li><li><strong><code>Count</code></strong> 数量</li><li><strong><code>Max</code></strong> 最大</li><li><strong><code>Min</code></strong> 最小</li><li><strong><code>Sum</code></strong> 求和</li></ul><p><strong>语法如下：</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> django<span class="token punctuation">.</span>db<span class="token punctuation">.</span>models <span class="token keyword">import</span> Sum<span class="token punctuation">,</span> Max<span class="token punctuation">,</span> Min<span class="token punctuation">,</span> Count<span class="token punctuation">,</span> Avg

Sum<span class="token punctuation">(</span><span class="token string">&#39;属性名&#39;</span><span class="token punctuation">)</span>  <span class="token comment"># 注意：属性名是字符串形式 </span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>1. 查询所有图书的平均阅读量</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>aggregate<span class="token punctuation">(</span>Avg<span class="token punctuation">(</span><span class="token string">&#39;bcomment&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span> 
<span class="token comment"># {&#39;bcomment__avg&#39;: 77.2}</span>
<span class="token comment"># 注意aggregate的返回值是一个字典类型，格式如下：</span>
<span class="token comment"># {&#39;属性名__聚合类小写&#39;: 值}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>2. 查询所有图书的数量</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>aggregate<span class="token punctuation">(</span>Count<span class="token punctuation">(</span><span class="token string">&#39;id&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 返回值也是一个字典格式， {&#39;id__count&#39;: 5}</span>

Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>count<span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token comment"># 使用count时一般不使用aggregate()过滤器, 注意：count函数的返回值是一个数字。</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="分组查询" tabindex="-1"><a class="header-anchor" href="#分组查询" aria-hidden="true">#</a> 分组查询</h4><p>分组查询一般会用到聚合函数，所以使用前要先从 <code>django.db.models</code> 引入 <code>Avg</code>,<code>Max</code>,<code>Min</code>,<code>Count</code>,<code>Sum</code>（首字母大写）</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> django<span class="token punctuation">.</span>db<span class="token punctuation">.</span>models <span class="token keyword">import</span> Avg<span class="token punctuation">,</span>Max<span class="token punctuation">,</span>Min<span class="token punctuation">,</span>Count<span class="token punctuation">,</span>Sum  <span class="token comment">#   引入函数</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>返回值：</strong></p><ul><li>分组后，用 <code>values</code> 取值，则返回值是 <code>QuerySet</code> ,数据类型里面为一个个字典；</li><li>分组后，用 <code>values_list</code> 取值，则返回值是 <code>QuerySet</code> ,数据类型里面为一个个元组。</li></ul><p>MySQL 中的 <code>limit</code> 相当于 ORM 中的 <code>QuerySet</code> 数据类型的切片。</p><p><strong>注意：</strong></p><p><code>annotate</code> 里面放聚合函数。</p><blockquote><p><code>values</code>函数放在 <code>annotate</code>函数之前，指明 按照什么字段分组</p><p><code>values</code>函数放在 <code>annotate</code>函数之后，指明 从分组结果中，取出哪些数据</p></blockquote><p><strong>1.查询每个作者的图书数量</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>source <span class="token operator">=</span> Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>vaues<span class="token punctuation">(</span><span class="token string">&#39;author__id&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>annotate<span class="token punctuation">(</span>total<span class="token operator">=</span>Sum<span class="token punctuation">(</span><span class="token string">&#39;name&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">.</span>values<span class="token punctuation">(</span><span class="token string">&#39;author__name&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;total&#39;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="关联查询" tabindex="-1"><a class="header-anchor" href="#关联查询" aria-hidden="true">#</a> 关联查询</h4><blockquote><p><code>key</code>:正向查询按字段,反向查询按表明小写</p></blockquote><h5 id="关联查询-1" tabindex="-1"><a class="header-anchor" href="#关联查询-1" aria-hidden="true">#</a> 关联查询</h5><h6 id="一对多" tabindex="-1"><a class="header-anchor" href="#一对多" aria-hidden="true">#</a> 一对多</h6><blockquote><p>通过 关联的 <strong>一</strong> 查询 <strong>多</strong>，如： <code>一个作者 ====&gt; 多本图书</code>， 查询<strong>作者</strong>对应的<strong>图书信息</strong></p></blockquote><p><strong>语法如下：</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>一对应的模型类对象<span class="token punctuation">.</span>多对应的模型类名小写_set
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>1. 查询 id为1的作者的所有图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>author <span class="token operator">=</span> Author<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>get<span class="token punctuation">(</span><span class="token builtin">id</span><span class="token operator">=</span><span class="token number">1</span><span class="token punctuation">)</span>  <span class="token comment"># 得到作者的模型类对象</span>

author<span class="token punctuation">.</span>book_set<span class="token punctuation">.</span><span class="token builtin">all</span><span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token comment"># 图书的 模型类名小写 + set ,然后 通过 all方法，得到 查询集</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h6 id="多对一" tabindex="-1"><a class="header-anchor" href="#多对一" aria-hidden="true">#</a> 多对一</h6><blockquote><p>通过 关联的 <strong>多</strong> 查询 <strong>一</strong>，如： <code>多本 图书 ====&gt; 一个作者</code>， 查询 <strong>图书</strong> 对应的 <strong>作者信息</strong></p></blockquote><p><strong>语法如下：</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>多对应的模型类对象<span class="token punctuation">.</span>多对应的模型类中的关系类属性名

多对应的模型类对象<span class="token punctuation">.</span>关联类属性_id
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>1. 查询id为1的图书的作者信息</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>book <span class="token operator">=</span> Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>get<span class="token punctuation">(</span><span class="token builtin">id</span><span class="token operator">=</span><span class="token number">1</span><span class="token punctuation">)</span>  <span class="token comment"># 得到图书 模型类对象</span>

book<span class="token punctuation">.</span>author <span class="token comment"># 对应的模型属性， 得到 作者对象</span>

book<span class="token punctuation">.</span>author_id  <span class="token comment"># 对应的模型属性_id, 得到 作者的id</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="关联过滤查询" tabindex="-1"><a class="header-anchor" href="#关联过滤查询" aria-hidden="true">#</a> 关联过滤查询</h5><h6 id="一对多-1" tabindex="-1"><a class="header-anchor" href="#一对多-1" aria-hidden="true">#</a> 一对多</h6><blockquote><p>通过 关联的 <strong>多</strong> 的<code>条件</code> 查询 <strong>一</strong>，如： <code>一个作者 ====&gt; 多本图书</code>， 根据<strong>图书的条件</strong> 查询 <strong>作者信息</strong></p></blockquote><p><strong>语法如下：</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>关联模型类名小写__属性名__条件运算符<span class="token operator">=</span>值
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>1. 查询名称包含&#39;Django&#39;的图书作者</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Author<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>book__btitle__contains<span class="token operator">=</span><span class="token string">&#39;Django&#39;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>2. 查询 阅读量大于500 的图书作者</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Author<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>book__bread__gt<span class="token operator">=</span><span class="token number">200</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h6 id="多对一-1" tabindex="-1"><a class="header-anchor" href="#多对一-1" aria-hidden="true">#</a> 多对一</h6><blockquote><p>通过 关联的 <strong>一</strong> 的<code>条件</code> 查询 <strong>多</strong>，如： <code>一个作者 ====&gt; 多本图书</code>， 根据<strong>作者的条件</strong> 查询 <strong>图书信息</strong></p></blockquote><p><strong>语法如下：</strong></p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>模型类关联属性名__模型类属性名__条件运算符=值
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>1. 查询 作者韩寒 的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>author__name<span class="token operator">=</span><span class="token string">&#39;韩寒&#39;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>2. 查询 作者id是1， 3， 4的图书</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Book<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span>author__id__in<span class="token operator">=</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="orm高级操作" tabindex="-1"><a class="header-anchor" href="#orm高级操作" aria-hidden="true">#</a> ORM高级操作</h2><p>本文主要针对的是模型类查询中的高级操作(如：聚合、分组等)做简单介绍。</p><h3 id="模型类" tabindex="-1"><a class="header-anchor" href="#模型类" aria-hidden="true">#</a> 模型类</h3><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 品牌</span>
<span class="token keyword">class</span> <span class="token class-name">Brand</span><span class="token punctuation">(</span>models<span class="token punctuation">.</span>Model<span class="token punctuation">)</span><span class="token punctuation">:</span>
    name <span class="token operator">=</span> models<span class="token punctuation">.</span>CharField<span class="token punctuation">(</span>max_length<span class="token operator">=</span><span class="token number">20</span><span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;品牌名&#39;</span><span class="token punctuation">)</span>

    <span class="token keyword">class</span> <span class="token class-name">Meta</span><span class="token punctuation">:</span>
        db_table <span class="token operator">=</span> <span class="token string">&#39;tb_brand&#39;</span>


<span class="token comment"># 分类</span>
<span class="token keyword">class</span> <span class="token class-name">Cate</span><span class="token punctuation">(</span>models<span class="token punctuation">.</span>Model<span class="token punctuation">)</span><span class="token punctuation">:</span>
    name <span class="token operator">=</span> models<span class="token punctuation">.</span>CharField<span class="token punctuation">(</span>max_length<span class="token operator">=</span><span class="token number">20</span><span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;分类名&#39;</span><span class="token punctuation">)</span>

    <span class="token keyword">class</span> <span class="token class-name">Meta</span><span class="token punctuation">:</span>
        db_table <span class="token operator">=</span> <span class="token string">&#39;tb_cate&#39;</span>


<span class="token comment"># 商品表： id、name、price、history、stock、 sales</span>
<span class="token keyword">class</span> <span class="token class-name">Goods</span><span class="token punctuation">(</span>models<span class="token punctuation">.</span>Model<span class="token punctuation">)</span><span class="token punctuation">:</span>
    cate <span class="token operator">=</span> models<span class="token punctuation">.</span>ForeignKey<span class="token punctuation">(</span>null<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">,</span> to<span class="token operator">=</span>Cate<span class="token punctuation">,</span> on_delete<span class="token operator">=</span>models<span class="token punctuation">.</span>CASCADE<span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;分类&#39;</span><span class="token punctuation">)</span>
    brand <span class="token operator">=</span> models<span class="token punctuation">.</span>ForeignKey<span class="token punctuation">(</span>null<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">,</span> to<span class="token operator">=</span>Brand<span class="token punctuation">,</span> on_delete<span class="token operator">=</span>models<span class="token punctuation">.</span>CASCADE<span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;品牌&#39;</span><span class="token punctuation">)</span>
    name <span class="token operator">=</span> models<span class="token punctuation">.</span>CharField<span class="token punctuation">(</span>max_length<span class="token operator">=</span><span class="token number">20</span><span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;商品名&#39;</span><span class="token punctuation">)</span>
    price <span class="token operator">=</span> models<span class="token punctuation">.</span>DecimalField<span class="token punctuation">(</span>max_digits<span class="token operator">=</span><span class="token number">10</span><span class="token punctuation">,</span> decimal_places<span class="token operator">=</span><span class="token number">2</span><span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;价格&#39;</span><span class="token punctuation">)</span>
    history <span class="token operator">=</span> models<span class="token punctuation">.</span>IntegerField<span class="token punctuation">(</span>default<span class="token operator">=</span><span class="token number">0</span><span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;浏览量&#39;</span><span class="token punctuation">)</span>
    stock <span class="token operator">=</span> models<span class="token punctuation">.</span>IntegerField<span class="token punctuation">(</span>default<span class="token operator">=</span><span class="token number">0</span><span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;库存&#39;</span><span class="token punctuation">)</span>
    sales <span class="token operator">=</span> models<span class="token punctuation">.</span>IntegerField<span class="token punctuation">(</span>default<span class="token operator">=</span><span class="token number">0</span><span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;销量&#39;</span><span class="token punctuation">)</span>

    <span class="token keyword">class</span> <span class="token class-name">Meta</span><span class="token punctuation">:</span>
        db_table <span class="token operator">=</span> <span class="token string">&#39;tb_goods&#39;</span>

<span class="token comment"># 订单：订单id、创建时间、更新时间、用户、总数、总价、实付金额、订单状态</span>
<span class="token keyword">class</span> <span class="token class-name">Order</span><span class="token punctuation">(</span>models<span class="token punctuation">.</span>Model<span class="token punctuation">)</span><span class="token punctuation">:</span>
    status_choices <span class="token operator">=</span> <span class="token punctuation">(</span>
        <span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token string">&#39;未支付&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
        <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token string">&#39;未收货&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
        <span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token string">&#39;未评价&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
        <span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">,</span> <span class="token string">&#39;已完成&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
    <span class="token punctuation">)</span>
    order_id <span class="token operator">=</span> models<span class="token punctuation">.</span>CharField<span class="token punctuation">(</span>max_length<span class="token operator">=</span><span class="token number">64</span><span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;订单号&#39;</span><span class="token punctuation">,</span> primary_key<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">)</span>
    create_time <span class="token operator">=</span> models<span class="token punctuation">.</span>DateTimeField<span class="token punctuation">(</span>auto_now_add<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;创建时间&#39;</span><span class="token punctuation">)</span>
    update_time <span class="token operator">=</span> models<span class="token punctuation">.</span>DateTimeField<span class="token punctuation">(</span>auto_now<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;更新时间&#39;</span><span class="token punctuation">)</span>
    user <span class="token operator">=</span> models<span class="token punctuation">.</span>ForeignKey<span class="token punctuation">(</span>to<span class="token operator">=</span>User<span class="token punctuation">,</span> on_delete<span class="token operator">=</span>models<span class="token punctuation">.</span>CASCADE<span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;用户&#39;</span><span class="token punctuation">)</span>
    total <span class="token operator">=</span> models<span class="token punctuation">.</span>IntegerField<span class="token punctuation">(</span>default<span class="token operator">=</span><span class="token number">0</span><span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;商品总数&#39;</span><span class="token punctuation">)</span>
    total_amount <span class="token operator">=</span> models<span class="token punctuation">.</span>DecimalField<span class="token punctuation">(</span>default<span class="token operator">=</span><span class="token number">0</span><span class="token punctuation">,</span> max_digits<span class="token operator">=</span><span class="token number">10</span><span class="token punctuation">,</span> decimal_places<span class="token operator">=</span><span class="token number">2</span><span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;商品总价&#39;</span><span class="token punctuation">)</span>
    pay_amount <span class="token operator">=</span> models<span class="token punctuation">.</span>DecimalField<span class="token punctuation">(</span>default<span class="token operator">=</span><span class="token number">0</span><span class="token punctuation">,</span> max_digits<span class="token operator">=</span><span class="token number">10</span><span class="token punctuation">,</span> decimal_places<span class="token operator">=</span><span class="token number">2</span><span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;实付金额&#39;</span><span class="token punctuation">)</span>
    status <span class="token operator">=</span> models<span class="token punctuation">.</span>SmallIntegerField<span class="token punctuation">(</span>choices<span class="token operator">=</span>status_choices<span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;订单状态&#39;</span><span class="token punctuation">)</span>

    <span class="token keyword">class</span> <span class="token class-name">Meta</span><span class="token punctuation">:</span>
        db_table <span class="token operator">=</span> <span class="token string">&#39;tb_order&#39;</span>


<span class="token comment"># 订单商品表：id、 name、price、num、goods_id(外键)、order_id(外键)、amount</span>
<span class="token keyword">class</span> <span class="token class-name">OrderGoods</span><span class="token punctuation">(</span>models<span class="token punctuation">.</span>Model<span class="token punctuation">)</span><span class="token punctuation">:</span>
    order <span class="token operator">=</span> models<span class="token punctuation">.</span>ForeignKey<span class="token punctuation">(</span>to<span class="token operator">=</span>Order<span class="token punctuation">,</span> related_name<span class="token operator">=</span><span class="token string">&#39;order_goods&#39;</span><span class="token punctuation">,</span> on_delete<span class="token operator">=</span>models<span class="token punctuation">.</span>CASCADE<span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;订单&#39;</span><span class="token punctuation">)</span>
    goods <span class="token operator">=</span> models<span class="token punctuation">.</span>ForeignKey<span class="token punctuation">(</span>to<span class="token operator">=</span>Goods<span class="token punctuation">,</span> related_name<span class="token operator">=</span><span class="token string">&#39;orders&#39;</span><span class="token punctuation">,</span> on_delete<span class="token operator">=</span>models<span class="token punctuation">.</span>CASCADE<span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;商品&#39;</span><span class="token punctuation">)</span>
    name <span class="token operator">=</span> models<span class="token punctuation">.</span>CharField<span class="token punctuation">(</span>max_length<span class="token operator">=</span><span class="token number">20</span><span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;商品名&#39;</span><span class="token punctuation">)</span>
    price <span class="token operator">=</span> models<span class="token punctuation">.</span>DecimalField<span class="token punctuation">(</span>max_digits<span class="token operator">=</span><span class="token number">10</span><span class="token punctuation">,</span> decimal_places<span class="token operator">=</span><span class="token number">2</span><span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;价格&#39;</span><span class="token punctuation">)</span>
    num <span class="token operator">=</span> models<span class="token punctuation">.</span>IntegerField<span class="token punctuation">(</span>verbose_name<span class="token operator">=</span><span class="token string">&#39;数量&#39;</span><span class="token punctuation">)</span>
    amount <span class="token operator">=</span> models<span class="token punctuation">.</span>DecimalField<span class="token punctuation">(</span>max_digits<span class="token operator">=</span><span class="token number">10</span><span class="token punctuation">,</span> decimal_places<span class="token operator">=</span><span class="token number">2</span><span class="token punctuation">,</span> verbose_name<span class="token operator">=</span><span class="token string">&#39;小计&#39;</span><span class="token punctuation">)</span>

    <span class="token keyword">class</span> <span class="token class-name">Meta</span><span class="token punctuation">:</span>
        db_table <span class="token operator">=</span> <span class="token string">&#39;tb_order_goods&#39;</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="查询" tabindex="-1"><a class="header-anchor" href="#查询" aria-hidden="true">#</a> 查询</h3><h4 id="聚合" tabindex="-1"><a class="header-anchor" href="#聚合" aria-hidden="true">#</a> 聚合</h4><p>聚合查询函数是对一组值执行计算，并返回单个值。</p><p>Django 使用聚合查询前要先从 <code>django.db.models</code> 引入 <code>Avg</code>、<code>Max</code>、<code>Min</code>、<code>Count</code>、<code>Sum</code>（首字母大写）。</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> django<span class="token punctuation">.</span>db<span class="token punctuation">.</span>models <span class="token keyword">import</span> Avg<span class="token punctuation">,</span>Max<span class="token punctuation">,</span>Min<span class="token punctuation">,</span>Count<span class="token punctuation">,</span>Sum  <span class="token comment">#   引入函数</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>聚合查询返回值的数据类型是字典。</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>aggregate<span class="token punctuation">(</span>别名 <span class="token operator">=</span> 聚合函数名<span class="token punctuation">(</span><span class="token string">&quot;属性名称&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol><li>查询所有订单的总价</li></ol><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Order<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>aggregate<span class="token punctuation">(</span><span class="token builtin">sum</span><span class="token operator">=</span>Sum<span class="token punctuation">(</span><span class="token string">&quot;total_amount&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="2"><li>查询所有商品的平均价格</li></ol><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Goods<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>aggregate<span class="token punctuation">(</span>avg<span class="token operator">=</span>Avg<span class="token punctuation">(</span><span class="token string">&quot;price&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="分组" tabindex="-1"><a class="header-anchor" href="#分组" aria-hidden="true">#</a> 分组</h4><p>分组查询一般会用到聚合函数，所以使用前要先从 <code>django.db.models</code> 引入 <code>Avg</code>,<code>Max</code>,<code>Min</code>,<code>Count</code>,<code>Sum</code>（首字母大写）</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> django<span class="token punctuation">.</span>db<span class="token punctuation">.</span>models <span class="token keyword">import</span> Avg<span class="token punctuation">,</span>Max<span class="token punctuation">,</span>Min<span class="token punctuation">,</span>Count<span class="token punctuation">,</span>Sum  <span class="token comment">#   引入函数</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>返回值:</strong></p><ul><li>分组后，用 <code>values</code> 取值，则返回值是 <code>QuerySet</code> ,数据类型里面为一个个字典；</li><li>分组后，用 <code>values_list</code> 取值，则返回值是 <code>QuerySet</code> ,数据类型里面为一个个元组。</li></ul><p>MySQL 中的 <code>limit</code> 相当于 ORM 中的 <code>QuerySet</code> 数据类型的切片。</p><p><strong>注意:</strong></p><p><code>annotate</code> 里面放聚合函数。</p><ul><li><strong><code>values</code></strong> 或者 <strong><code>values_list</code></strong> 放在 annotate 前面 :values 或者 values_list 是声明以什么字段分组，annotate 执行分组。</li><li><strong><code>values</code></strong> 或者 <strong><code>values_list</code></strong> 放在annotate后面：annotate 表示直接以当前表的pk执行分组，values 或者 values_list 表示查询哪些字段， 并且要将 annotate 里的聚合函数起别名，在 values 或者 values_list 里写其别名。</li></ul><ol><li>查询每天的订单量、销售额</li></ol><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>Order<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>\\
annotate<span class="token punctuation">(</span>day<span class="token operator">=</span>TruncDay<span class="token punctuation">(</span><span class="token string">&#39;create_time&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">.</span>\\  <span class="token comment"># 将订单对象，添加一个新字段</span>
<span class="token comment"># 按照日期分组，然后对 分组结果 进行聚合计算</span>
values<span class="token punctuation">(</span><span class="token string">&#39;day&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>annotate<span class="token punctuation">(</span>total<span class="token operator">=</span>Count<span class="token punctuation">(</span><span class="token string">&#39;id&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span><span class="token builtin">sum</span><span class="token operator">=</span>Sum<span class="token punctuation">(</span><span class="token string">&#39;total_amount&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">.</span>\\
<span class="token comment"># 从聚合结果中，查询哪些字段</span>
values<span class="token punctuation">(</span><span class="token string">&#39;day&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;total&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;sum&#39;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>查询每天商品的销售额</li></ol><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>OrderGoods<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>annotate<span class="token punctuation">(</span>day<span class="token operator">=</span>TruncDay<span class="token punctuation">(</span><span class="token string">&#39;order__create_time&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">.</span>values<span class="token punctuation">(</span><span class="token string">&#39;day&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>annotate<span class="token punctuation">(</span><span class="token builtin">sum</span><span class="token operator">=</span>Sum<span class="token punctuation">(</span><span class="token string">&#39;amount&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">.</span>values<span class="token punctuation">(</span><span class="token string">&#39;day&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;sum&#39;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="3"><li>查询每个品牌商品的销售额</li></ol><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>OrderGoods<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>values<span class="token punctuation">(</span><span class="token string">&#39;goods__brand__name&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>annotate<span class="token punctuation">(</span><span class="token builtin">sum</span><span class="token operator">=</span>Sum<span class="token punctuation">(</span><span class="token string">&#39;amount&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="4"><li>查询每类商品的销售额</li></ol><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>OrderGoods<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>values<span class="token punctuation">(</span><span class="token string">&#39;goods__cate__name&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>annotate<span class="token punctuation">(</span><span class="token builtin">sum</span><span class="token operator">=</span>Sum<span class="token punctuation">(</span><span class="token string">&#39;amount&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="5"><li>查询每天用户新增量</li></ol><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>User<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>annotate<span class="token punctuation">(</span>day<span class="token operator">=</span>TruncDay<span class="token punctuation">(</span><span class="token string">&#39;date_joined&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">.</span>values<span class="token punctuation">(</span><span class="token string">&#39;day&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>annotate<span class="token punctuation">(</span>n<span class="token operator">=</span>Count<span class="token punctuation">(</span><span class="token string">&#39;id&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,185),p=[o];function c(l,i){return s(),a("div",null,p)}const d=n(e,[["render",c],["__file","ORM操作.html.vue"]]);export{d as default};
